import { cursor } from './cursor';
import { gamePaused } from '../gamestore';
import { gameStore } from '../gamestore';
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
	[cursor, gameStore, gamePaused],
	([$cursor, $gameStore, $gamePaused]) => {
		if ($cursor.x === null || $cursor.y === null) {
			return true;
		}

		const currentValue = $gameStore.getSudoku().getGrid()[$cursor.y][$cursor.x];
		return currentValue !== 0 || $gamePaused;
	},
	false,
);